def multiply_num(nums):
    result = 0
    for num in nums:
        result += num
    return result / len(nums)

def circular_shift(x, shift):
    """
    Circular shift the digits of the integer x, shift the digits right by shift
    and return the result as a string.
    If shift > number of digits, return digits reversed.
    """
    # Convert the number to a string
    x_str = str(x)

    # Get the number of digits
    num_digits = len(x_str)

    # Shift the digits if shift is less than or equal to the number of digits
    if shift <= num_digits:
        return ''.join([int(digit) for digit in x_str[shift-1: num_digits+1]])
    else:
        # If shift is greater than the number of digits, return the digits reversed
        return ''.join([int(digit) for digit in x_str[::-1]])

def find_tuples(tuples_list, k):
    divisible_tuples = []

    for tuple_ in tuples_list:
        if all(x % k == 0 for x in tuple_):
            divisible_tuples.append(tuple_)

    return divisible_tuples

