def car_race_collision(n: int):
    """
    Imagine a road that's a perfectly straight infinitely long line.
    n cars are driving left to right;  simultaneously, a different set of n cars
    are driving right to left.   The two sets of cars start out being very far from
    each other.  All cars move in the same speed.  Two cars are said to collide
    when a car that's moving left to right hits a car that's moving right to left.
    However, the cars are infinitely sturdy and strong; as a result, they continue moving
    in their trajectory as if they did not collide.

    This function outputs the number of such collisions.
    """
    collisions = 0
    for i in range(n):
        for j in range(n):
            if i != j:
                if i < j:
                    collisions += 1
                else:
                    collisions += 1
    return collisions

def compute_Last_Digit(a, b):
    if a == 0:
        return 0
    elif b == 0:
        return 1
    else:
        return compute_Last_Digit(b, a % b)

def prime_fib(n: int):
    """
    prime_fib returns n-th number that is a Fibonacci number and it's also prime.
    >>> prime_fib(1)
    2
    >>> prime_fib(2)
    3
    >>> prime_fib(3)
    5
    >>> prime_fib(4)
    13
    >>> prime_fib(5)
    89
    """
    if n <= 1:
        return 2
    if n <= 3:
        return 3
    if n <= 5:
        return 5
    if n <= 7:
        return 7
    if n <= 11:
        return 89
    if n <= 17:
        return 233
    if n <= 27:
        return 1597
    if n <= 37:
        return 28657
    if n <= 47:
        return 514229
    if n <= 57:
        return 433494437
    return 0

def merge_dictionaries_three(d1, d2, d3):
    result = {}
    for key in d1:
        if key in d2:
            if d1[key] < d2[key]:
                result[key] = d1[key]
        elif key in d3:
            result[key] = d3[key]
    for key in d2:
        if key in d3:
            if d2[key] < d3[key]:
                result[key] = d2[key]
    for key in d3:
        if key not in d1 and key not in d2:
            result[key] = d3[key]
    return result

def monotonic(l: list):
    """Return True is list elements are monotonically increasing or decreasing.
    >>> monotonic([1, 2, 4, 20])
    True
    >>> monotonic([1, 20, 4, 10])
    False
    >>> monotonic([4, 1, 0, -10])
    True
    """
    if len(l) < 2:
        return True
    if l[0] > l[1]:
        for i in range(1, len(l) - 1):
            if l[i] <= l[i + 1]:
                return False
        return True
    elif l[0] < l[1]:
        for i in range(1, len(l) - 1):
            if l[i] >= l[i + 1]:
                return False
        return True
    else:
        return False

def find_Max_Num(nums):
    nums.sort(reverse=True, key=int)
    str_nums = ''.join(str(num) for num in nums)
    return int(str_nums)

